Index: bench-targets/cli-flags/src/parseArgs.mjs
===================================================================
--- bench-targets/cli-flags/src/parseArgs.mjs	
+++ bench-targets/cli-flags/src/parseArgs.mjs	
@@ -1,9 +1,21 @@
 export function parseArgs(argv) {
   const result = { _: [] }
-  for (let index = 0; index < argv.length; index += 1) {
-    const arg = argv[index]
-    if (!arg.startsWith('--')) result._.push(arg)
-    else result[arg.slice(2)] = true
+  for (let i = 0; i < argv.length; i++) {
+    const arg = argv[i]
+    if (arg === undefined) continue
+    if (arg.startsWith('-') && arg !== '-') {
+      if (arg.includes('=')) {
+        const [key, value] = arg.split('=')
+        result[key.substring(2)] = value
+      } else if (argv[i + 1] !== undefined && !argv[i + 1].startsWith('-')) {
+        result[arg.slice(2)] = argv[i + 1]
+        i++
+      } else {
+        result[arg.slice(2)] = true
+      }
+    } else {
+      result._.push(arg)
+    }
   }
   return result
 }

